fun solve(nums: Array<Long>, k: Long): Long {
    val totalSum = nums.sum()
    var prefixSum = 0L
    var dp = 0L
    val hashMap = HashMap<Long, Long>()
    hashMap[0L] = 0L
    for (num in nums) {
        prefixSum += num
        val mod = prefixSum % k
        var currentMax = -Long.MAX_VALUE
        if (hashMap.containsKey(mod)) {
            currentMax = hashMap[mod]!! + prefixSum
        }
        val newDp = Math.max(dp, currentMax)
        if (hashMap.containsKey(mod)) {
            val newValue = newDp - prefixSum
            hashMap[mod] = Math.max(hashMap[mod]!!, newValue)
        } else {
            hashMap[mod] = newDp - prefixSum
        }
        dp = newDp
    }
    return totalSum - dp
}
